import React, { useState, useEffect, useCallback, useRef } from 'react';
import { getApiBase } from '../utils/platform';
import { tokens } from '../styles/tokens';
import s from './WalkForwardPage.module.css';

const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, muted: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};

const mono = tokens.font.mono;

/* ── tiny helpers ─────────────────────────────────────────────── */
function fmt(n, d = 2) { return n == null || isNaN(n) ? '-' : Number(n).toFixed(d); }
function fmtPF(n) { return n == null || isNaN(n) ? '-' : n >= 50 ? '\u221E' : Number(n).toFixed(2); }
function fmtDollar(n) { return n == null || isNaN(n) ? '-' : `$${Number(n).toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 0 })}`; }
function fmtPct(n) { return n == null || isNaN(n) ? '-' : `${Number(n).toFixed(1)}%`; }
function fmtDate(ts) {
  if (!ts) return '';
  const d = typeof ts === 'number' ? new Date(ts * 1000) : new Date(ts);
  return d.toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' });
}
function assessColor(a) {
  if (!a) return C.muted;
  if (a === 'minimal_overfitting') return C.green;
  if (a === 'moderate_overfitting') return C.amber;
  return C.red;
}
function valColor(val, good, warn) {
  if (val == null || isNaN(val)) return C.muted;
  if (val >= good) return C.green;
  if (val >= warn) return C.amber;
  return C.red;
}
function pctChange(train, test) {
  if (!train || !test || isNaN(train) || isNaN(test) || train === 0) return null;
  return ((test - train) / Math.abs(train)) * 100;
}

/* ── reusable components ─────────────────────────────────────── */
function Card({ children, className, style }) {
  return (
    <div className={`${s.card} ${className || ''}`} style={style}>
      {children}
    </div>
  );
}

function Metric({ label, value, color = C.text, sub }) {
  return (
    <div className={s.metric}>
      <div className={s.metricLabel}>{label}</div>
      <div className={s.metricValue} style={{ color }}>{value}</div>
      {sub && <div className={s.metricSub}>{sub}</div>}
    </div>
  );
}

function ProgressBar({ pct, window: win, totalWindows, phase, startTime }) {
  const elapsed = startTime ? Math.floor((Date.now() - startTime) / 1000) : 0;
  const eta = pct > 2 ? Math.round(elapsed * (100 - pct) / pct) : null;
  const fmtTime = (sec) => sec >= 60 ? `${Math.floor(sec / 60)}m ${sec % 60}s` : `${sec}s`;
  const pctClamped = Math.min(Math.max(pct || 0, 0), 100);

  return (
    <div>
      <div className={s.progressTopRow}>
        <span className={s.progressWindowLabel}>
          {win > 0 && totalWindows > 0 ? `Window ${win} of ${totalWindows}` : 'Initializing...'}
        </span>
        <span className={s.progressPct}>
          {fmt(pctClamped, 1)}%
        </span>
      </div>

      <div className={s.progressTrack}>
        <div className={s.progressFill} style={{
          width: `${pctClamped}%`,
          boxShadow: pctClamped > 0 ? `0 0 8px ${C.blue}44` : 'none',
        }} />
      </div>

      <div className={s.progressBottomRow}>
        <span>{phase || 'starting'}</span>
        <span>
          {elapsed > 0 && <>{fmtTime(elapsed)} elapsed</>}
          {eta != null && <> &middot; ~{fmtTime(eta)} remaining</>}
        </span>
      </div>
    </div>
  );
}

function Spinner({ size = 16, color = C.muted }) {
  return (
    <svg width={size} height={size} viewBox="0 0 38 38" stroke={color} className={s.spinner}>
      <g fill="none" fillRule="evenodd"><g transform="translate(1 1)" strokeWidth="2">
        <circle strokeOpacity=".3" cx="18" cy="18" r="18" />
        <path d="M36 18c0-9.94-8.06-18-18-18">
          <animateTransform attributeName="transform" type="rotate" from="0 18 18" to="360 18 18" dur="1s" repeatCount="indefinite" />
        </path>
      </g></g>
    </svg>
  );
}

/* ── SVG equity curve ────────────────────────────────────────── */
function EquityCurve({ windows }) {
  if (!windows || windows.length < 2) return null;

  let equity = 100000;
  const points = [{ x: 0, y: equity, label: 'Start' }];
  for (let i = 0; i < windows.length; i++) {
    const w = windows[i];
    const pnl = w.test_metrics?.total_pnl || 0;
    equity += pnl;
    points.push({ x: i + 1, y: equity, label: `W${w.window_id}` });
  }

  const minY = Math.min(...points.map(p => p.y));
  const maxY = Math.max(...points.map(p => p.y));
  const rangeY = maxY - minY || 1;
  const W = 700, H = 200, pad = 40;

  const toSvg = (i, val) => ({
    sx: pad + (i / (points.length - 1)) * (W - 2 * pad),
    sy: pad + (1 - (val - minY) / rangeY) * (H - 2 * pad),
  });

  const polyline = points.map((p, i) => {
    const { sx, sy } = toSvg(i, p.y);
    return `${sx},${sy}`;
  }).join(' ');

  const finalColor = equity >= 100000 ? C.green : C.red;

  return (
    <div className={s.equityCurveWrap}>
      <svg width={W} height={H} className={s.equityCurveSvg}>
        {[0, 0.25, 0.5, 0.75, 1].map(f => {
          const y = pad + f * (H - 2 * pad);
          const val = maxY - f * rangeY;
          return (
            <g key={f}>
              <line x1={pad} y1={y} x2={W - pad} y2={y} stroke={C.border} strokeDasharray="4,4" />
              <text x={pad - 4} y={y + 4} fill={C.muted} fontSize={10} fontFamily={mono} textAnchor="end">
                {fmtDollar(val)}
              </text>
            </g>
          );
        })}
        {(() => {
          const { sy } = toSvg(0, 100000);
          return <line x1={pad} y1={sy} x2={W - pad} y2={sy} stroke={C.muted} strokeDasharray="2,4" strokeOpacity={0.5} />;
        })()}
        <polyline fill="none" stroke={finalColor} strokeWidth="2.5" points={polyline} />
        {points.map((p, i) => {
          const { sx, sy } = toSvg(i, p.y);
          return <circle key={i} cx={sx} cy={sy} r={3} fill={finalColor} />;
        })}
        {points.filter((_, i) => i % Math.max(1, Math.floor(points.length / 8)) === 0 || i === points.length - 1).map((p) => {
          const idx = points.indexOf(p);
          const { sx } = toSvg(idx, p.y);
          return (
            <text key={idx} x={sx} y={H - 8} fill={C.muted} fontSize={10} fontFamily={mono} textAnchor="middle">
              {p.label}
            </text>
          );
        })}
      </svg>
    </div>
  );
}

/* ── Parameter stability sparkline chart ─────────────────────── */
function ParamSparkline({ values, color = C.purple, width = 120, height = 32 }) {
  if (!values || values.length < 2) return null;
  const W = width, H = height;
  const min = Math.min(...values);
  const max = Math.max(...values);
  const range = max - min || 1;
  const pts = values.map((v, i) => {
    const x = (i / (values.length - 1)) * W;
    const y = H - ((v - min) / range) * H;
    return `${x},${y}`;
  }).join(' ');

  return (
    <svg width={W} height={H} className={s.sparklineSvg}>
      <polyline fill="none" stroke={color} strokeWidth="2" points={pts} />
    </svg>
  );
}

/* ── Confidence interval bar ─────────────────────────────────── */
function CIBar({ label, ci, unit = '' }) {
  if (!ci || ci.n < 2) return null;
  const lo = ci.ci_low;
  const hi = ci.ci_high;
  const mean = ci.mean;
  const barMin = lo - (hi - lo) * 0.3;
  const barMax = hi + (hi - lo) * 0.3;
  const barRange = barMax - barMin || 1;
  const loPct = ((lo - barMin) / barRange) * 100;
  const hiPct = ((hi - barMin) / barRange) * 100;
  const meanPct = ((mean - barMin) / barRange) * 100;

  return (
    <div className={s.ciBarWrap}>
      <div className={s.ciBarHeader}>
        <span className={s.ciBarLabel}>{label.replace(/_/g, ' ')}</span>
        <span className={s.ciBarValues}>{fmt(mean, 3)}{unit} [{fmt(lo, 3)}, {fmt(hi, 3)}]</span>
      </div>
      <div className={s.ciBarTrack}>
        <div className={s.ciBarRange} style={{ left: `${loPct}%`, width: `${hiPct - loPct}%` }} />
        <div className={s.ciBarMean} style={{ left: `${meanPct}%` }} />
      </div>
    </div>
  );
}

/* ── Sensitivity bar chart ───────────────────────────────────── */
function SensitivityChart({ data }) {
  if (!data || !data.performance_by_value) return null;
  const entries = Object.entries(data.performance_by_value).sort((a, b) => Number(a[0]) - Number(b[0]));
  if (entries.length === 0) return null;
  const maxPF = Math.max(...entries.map(([, v]) => v.avg_pf), 1);

  return (
    <div className={s.sensitivityRow}>
      {entries.map(([val, metrics]) => {
        const h = Math.max(4, (metrics.avg_pf / maxPF) * 56);
        const isMax = val === String(data.best_value);
        return (
          <div key={val} className={s.sensitivityCol}>
            <div style={{
              width: '100%', maxWidth: 28, height: h,
              background: isMax ? C.green : C.blue,
              borderRadius: '3px 3px 0 0',
              opacity: isMax ? 1 : 0.6,
            }} title={`Value: ${val}, Avg PF: ${fmt(metrics.avg_pf, 3)}, Count: ${metrics.count}`} />
            <div className={s.sensitivityBarLabel}>{val}</div>
          </div>
        );
      })}
    </div>
  );
}

/* ── Train vs Test comparison metric ─────────────────────────── */
function ComparisonMetric({ label, trainVal, testVal, formatter, goodThreshold, warnThreshold, higherIsBetter = true }) {
  const fmtFn = formatter || fmt;
  const change = pctChange(trainVal, testVal);
  const changeGood = higherIsBetter ? (change != null && change >= 0) : (change != null && change <= 0);

  return (
    <div className={s.compMetric}>
      <div className={s.compMetricLabel}>{label}</div>
      <div className={s.compMetricRow}>
        <div className={s.compMetricCell}>
          <div className={s.compMetricCellLabel}>TRAIN</div>
          <div className={s.compMetricCellValue} style={{ color: C.blue }}>
            {fmtFn(trainVal)}
          </div>
        </div>
        <div className={s.compMetricArrow}>
          <svg width="20" height="12" viewBox="0 0 20 12">
            <path d="M0 6h16M12 1l5 5-5 5" fill="none" stroke={C.muted} strokeWidth="1.5" />
          </svg>
        </div>
        <div className={s.compMetricCell}>
          <div className={s.compMetricCellLabel}>TEST</div>
          <div className={s.compMetricCellValue} style={{
            color: goodThreshold != null
              ? valColor(testVal, goodThreshold, warnThreshold ?? goodThreshold * 0.7)
              : C.text,
          }}>
            {fmtFn(testVal)}
          </div>
        </div>
      </div>
      {change != null && (
        <div className={s.compMetricDelta} style={{ color: changeGood ? C.green : C.red }}>
          {change >= 0 ? '+' : ''}{fmt(change, 1)}% degradation
        </div>
      )}
    </div>
  );
}

/* ── Stability score gauge ───────────────────────────────────── */
function StabilityGauge({ score, label }) {
  if (score == null || isNaN(score)) return null;
  const pct = Math.max(0, Math.min(1, score)) * 100;
  const color = score >= 0.7 ? C.green : score >= 0.4 ? C.amber : C.red;
  const rating = score >= 0.8 ? 'Excellent' : score >= 0.7 ? 'Good' : score >= 0.5 ? 'Fair' : score >= 0.3 ? 'Poor' : 'Unstable';
  const W = 200, H = 110, cx = 100, cy = 100, r = 80;
  const startAngle = Math.PI;
  const endAngle = 0;
  const angle = startAngle - (startAngle - endAngle) * Math.min(1, score);
  const x1 = cx + r * Math.cos(startAngle);
  const y1 = cy - r * Math.sin(startAngle);
  const x2 = cx + r * Math.cos(angle);
  const y2 = cy - r * Math.sin(angle);
  const largeArc = (startAngle - angle) > Math.PI ? 1 : 0;

  return (
    <div className={s.gaugeWrap}>
      <svg width={W} height={H} viewBox={`0 0 ${W} ${H}`}>
        {/* Background arc */}
        <path
          d={`M ${cx + r * Math.cos(startAngle)} ${cy - r * Math.sin(startAngle)} A ${r} ${r} 0 1 1 ${cx + r * Math.cos(endAngle)} ${cy - r * Math.sin(endAngle)}`}
          fill="none" stroke={C.border} strokeWidth="10" strokeLinecap="round"
        />
        {/* Value arc */}
        {score > 0 && (
          <path
            d={`M ${x1} ${y1} A ${r} ${r} 0 ${largeArc} 1 ${x2} ${y2}`}
            fill="none" stroke={color} strokeWidth="10" strokeLinecap="round"
          />
        )}
        <text x={cx} y={cy - 15} fill={color} fontSize="28" fontWeight="700" fontFamily={mono} textAnchor="middle">
          {fmt(score, 2)}
        </text>
        <text x={cx} y={cy + 5} fill={C.muted} fontSize="12" textAnchor="middle">
          {rating}
        </text>
      </svg>
      {label && <div className={s.gaugeLabel}>{label}</div>}
    </div>
  );
}

/* ── Parameter drift chart (SVG multi-line) ──────────────────── */
function ParamDriftChart({ paramStability, windows }) {
  const params = ['stop_loss', 'take_profit', 'max_hold_days', 'trailing_stop', 'min_score']
    .filter(k => paramStability[k] && paramStability[k].values && paramStability[k].values.length >= 2);
  if (params.length === 0) return null;

  const W = 680, H = 220, pad = { top: 20, right: 20, bottom: 36, left: 60 };
  const chartW = W - pad.left - pad.right;
  const chartH = H - pad.top - pad.bottom;
  const colors = [C.blue, C.green, C.amber, C.purple, C.red];

  return (
    <div className={s.driftChartWrap}>
      <svg width={W} height={H} className={s.equityCurveSvg}>
        {/* Grid lines */}
        {[0, 0.25, 0.5, 0.75, 1].map(f => {
          const y = pad.top + f * chartH;
          return <line key={f} x1={pad.left} y1={y} x2={W - pad.right} y2={y}
            stroke={C.border} strokeDasharray="3,3" />;
        })}

        {/* Each parameter as a normalized line */}
        {params.map((pk, pi) => {
          const vals = paramStability[pk].values;
          const min = Math.min(...vals);
          const max = Math.max(...vals);
          const range = max - min || 1;
          const pts = vals.map((v, i) => {
            const x = pad.left + (i / (vals.length - 1)) * chartW;
            const y = pad.top + (1 - (v - min) / range) * chartH;
            return `${x},${y}`;
          }).join(' ');

          return (
            <g key={pk}>
              <polyline fill="none" stroke={colors[pi % colors.length]} strokeWidth="2" points={pts} />
              {vals.map((v, i) => {
                const x = pad.left + (i / (vals.length - 1)) * chartW;
                const y = pad.top + (1 - (v - min) / range) * chartH;
                return <circle key={i} cx={x} cy={y} r={2.5} fill={colors[pi % colors.length]} />;
              })}
            </g>
          );
        })}

        {/* X-axis window labels */}
        {(() => {
          const sampleLen = params.length > 0 ? paramStability[params[0]].values.length : 0;
          const labels = [];
          for (let i = 0; i < sampleLen; i++) {
            if (sampleLen <= 12 || i % Math.max(1, Math.floor(sampleLen / 8)) === 0 || i === sampleLen - 1) {
              const x = pad.left + (i / (sampleLen - 1)) * chartW;
              labels.push(
                <text key={i} x={x} y={H - 8} fill={C.muted} fontSize={10} fontFamily={mono} textAnchor="middle">
                  W{i + 1}
                </text>
              );
            }
          }
          return labels;
        })()}

        {/* Y-axis labels */}
        <text x={pad.left - 4} y={pad.top + 4} fill={C.muted} fontSize={10} fontFamily={mono} textAnchor="end">High</text>
        <text x={pad.left - 4} y={pad.top + chartH + 4} fill={C.muted} fontSize={10} fontFamily={mono} textAnchor="end">Low</text>
      </svg>

      {/* Legend */}
      <div className={s.driftLegend}>
        {params.map((pk, pi) => (
          <div key={pk} className={s.driftLegendItem}>
            <div className={s.driftLegendSwatch} style={{ background: colors[pi % colors.length] }} />
            <span>{pk.replace(/_/g, ' ')}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

/* ── Window performance mini-bar chart (train vs test PF) ────── */
function WindowBarChart({ windows }) {
  if (!windows || windows.length === 0) return null;
  const maxVal = Math.max(
    ...windows.map(w => Math.max(w.train_metrics?.pf || 0, w.test_metrics?.pf || 0)),
    1
  );
  const W = 680, H = 160;
  const barGroupWidth = Math.min(60, (W - 40) / windows.length);
  const barWidth = barGroupWidth * 0.35;
  const gap = barGroupWidth * 0.1;
  const chartLeft = 40;
  const chartH = H - 40;

  return (
    <div className={s.equityCurveWrap}>
      <svg width={W} height={H} className={s.equityCurveSvg}>
        {/* Grid lines */}
        {[0, 0.5, 1].map(f => {
          const y = 10 + (1 - f) * chartH;
          const val = f * maxVal;
          return (
            <g key={f}>
              <line x1={chartLeft} y1={y} x2={W - 10} y2={y} stroke={C.border} strokeDasharray="3,3" />
              <text x={chartLeft - 4} y={y + 4} fill={C.muted} fontSize={10} fontFamily={mono} textAnchor="end">
                {fmtPF(val)}
              </text>
            </g>
          );
        })}

        {/* PF = 1.0 baseline */}
        {maxVal > 1 && (() => {
          const y = 10 + (1 - 1 / maxVal) * chartH;
          return <line x1={chartLeft} y1={y} x2={W - 10} y2={y} stroke={C.amber} strokeDasharray="2,4" strokeOpacity={0.5} />;
        })()}

        {/* Bars */}
        {windows.map((w, i) => {
          const trainPF = w.train_metrics?.pf || 0;
          const testPF = w.test_metrics?.pf || 0;
          const x = chartLeft + i * barGroupWidth + gap;
          const trainH = (trainPF / maxVal) * chartH;
          const testH = (testPF / maxVal) * chartH;
          const trainY = 10 + chartH - trainH;
          const testY = 10 + chartH - testH;

          return (
            <g key={w.window_id}>
              <rect x={x} y={trainY} width={barWidth} height={trainH} rx={2}
                fill={C.blue} opacity={0.7}>
                <title>W{w.window_id} Train PF: {fmtPF(trainPF)}</title>
              </rect>
              <rect x={x + barWidth + 1} y={testY} width={barWidth} height={testH} rx={2}
                fill={testPF >= 1 ? C.green : C.red} opacity={0.8}>
                <title>W{w.window_id} Test PF: {fmtPF(testPF)}</title>
              </rect>
              <text x={x + barWidth} y={H - 6} fill={C.muted} fontSize={9} fontFamily={mono} textAnchor="middle">
                W{w.window_id}
              </text>
            </g>
          );
        })}

        {/* Legend in top-right */}
        <rect x={W - 115} y={4} width={10} height={10} rx={2} fill={C.blue} opacity={0.7} />
        <text x={W - 102} y={13} fill={C.muted} fontSize={10}>Train PF</text>
        <rect x={W - 115} y={18} width={10} height={10} rx={2} fill={C.green} opacity={0.8} />
        <text x={W - 102} y={27} fill={C.muted} fontSize={10}>Test PF</text>
      </svg>
    </div>
  );
}

/* ── Window stability heatmap row ────────────────────────────── */
function StabilityHeatmap({ windows }) {
  if (!windows || windows.length === 0) return null;
  const passing = windows.filter(w => (w.test_metrics?.pf || 0) >= 1).length;
  const passRate = (passing / windows.length) * 100;

  return (
    <div>
      <div className={s.heatmapHeader}>
        <span>Window Pass Rate (Test PF &ge; 1.0)</span>
        <span style={{ fontFamily: mono, fontWeight: 700, color: passRate >= 70 ? C.green : passRate >= 50 ? C.amber : C.red }}>
          {passing}/{windows.length} ({fmt(passRate, 0)}%)
        </span>
      </div>
      <div className={s.heatmapRow}>
        {windows.map(w => {
          const testPF = w.test_metrics?.pf || 0;
          const pass = testPF >= 1;
          return (
            <div
              key={w.window_id}
              className={s.heatmapCell}
              style={{
                background: pass ? `${C.green}30` : `${C.red}30`,
                borderColor: pass ? `${C.green}60` : `${C.red}60`,
              }}
              title={`W${w.window_id}: Test PF ${fmtPF(testPF)}`}
            >
              <div style={{ fontSize: 9, color: C.muted }}>W{w.window_id}</div>
              <div style={{ fontSize: 11, fontFamily: mono, fontWeight: 700, color: pass ? C.green : C.red }}>
                {fmtPF(testPF)}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}


/* ── Auth-aware fetch helper ────────────────────────────────── */
function authFetch(url, opts = {}) {
  const token = localStorage.getItem('aura_token');
  const headers = { ...(opts.headers || {}) };
  if (token) headers['Authorization'] = `Bearer ${token}`;
  return fetch(url, { ...opts, headers });
}

/* ===================================================================
   MAIN PAGE COMPONENT
   =================================================================== */
export default function WalkForwardPage() {
  const API = getApiBase();

  // Config
  const [strategy, setStrategy] = useState('all');
  const [totalPeriod, setTotalPeriod] = useState(10);
  const [trainWindow, setTrainWindow] = useState(3);
  const [testWindow, setTestWindow] = useState(1);
  const [stepMonths, setStepMonths] = useState(6);
  const [symbolList, setSymbolList] = useState('');

  // Strategy list for dropdown
  const [strategies, setStrategies] = useState([]);

  // Job state
  const [runningJob, setRunningJob] = useState(null);
  const [progress, setProgress] = useState(null);
  const [runStartTime, setRunStartTime] = useState(null);
  const pollRef = useRef(null);

  // Results
  const [results, setResults] = useState(null);
  const [sensitivity, setSensitivity] = useState(null);
  const [resultsLoading, setResultsLoading] = useState(false);
  const [resultsError, setResultsError] = useState(null);

  // History
  const [history, setHistory] = useState([]);
  const [runningJobs, setRunningJobs] = useState([]);
  const [selectedJobId, setSelectedJobId] = useState(null);

  // Tabs
  const [tab, setTab] = useState('overview');

  // Errors
  const [configError, setConfigError] = useState(null);
  const [runError, setRunError] = useState(null);

  // Load strategy list
  useEffect(() => {
    authFetch(`${API}/strategies`)
      .then(r => r.ok ? r.json() : { strategies: [] })
      .then(d => {
        const list = (d.strategies || d || []).map(s => s.key || s.name || s).filter(Boolean);
        setStrategies(list.sort());
      })
      .catch(() => {});
  }, [API]);

  // Load history
  const fetchHistory = useCallback(() => {
    authFetch(`${API}/walk-forward/history?limit=50`)
      .then(r => r.ok ? r.json() : { history: [], running: [] })
      .then(d => {
        setHistory(d.history || []);
        setRunningJobs(d.running || []);
      })
      .catch(() => {});
  }, [API]);

  useEffect(() => {
    fetchHistory();
    const iv = setInterval(fetchHistory, 10000);
    return () => clearInterval(iv);
  }, [fetchHistory]);

  // Config validation
  useEffect(() => {
    setConfigError(null);
    if (trainWindow + testWindow > totalPeriod) {
      setConfigError('Train + Test windows exceed total period.');
    }
  }, [trainWindow, testWindow, totalPeriod]);

  // Poll progress
  useEffect(() => {
    if (!runningJob) {
      if (pollRef.current) { clearInterval(pollRef.current); pollRef.current = null; }
      return;
    }
    const jobId = runningJob.job_id;
    const poll = () => {
      authFetch(`${API}/walk-forward/progress/${jobId}`)
        .then(r => r.ok ? r.json() : null)
        .then(d => {
          if (!d) return;
          setProgress(d);
          if (d.status === 'complete' || d.status === 'completed' || d.status === 'failed') {
            clearInterval(pollRef.current);
            pollRef.current = null;
            setRunningJob(null);
            if (d.status !== 'failed') {
              loadResults(jobId);
            } else {
              setRunError(d.error || 'Job failed');
            }
            fetchHistory();
          }
        })
        .catch(() => {});
    };
    poll();
    pollRef.current = setInterval(poll, 2000);
    return () => { if (pollRef.current) { clearInterval(pollRef.current); pollRef.current = null; } };
  }, [runningJob, API, fetchHistory]);

  // Load results
  const loadResults = useCallback((jobId) => {
    setResultsLoading(true);
    setResultsError(null);
    setResults(null);
    setSensitivity(null);
    setSelectedJobId(jobId);
    setTab('overview');

    authFetch(`${API}/walk-forward/results/${jobId}`)
      .then(r => { if (!r.ok) throw new Error(r.statusText); return r.json(); })
      .then(d => setResults(d))
      .catch(e => setResultsError(e.message))
      .finally(() => setResultsLoading(false));

    authFetch(`${API}/walk-forward/sensitivity/${jobId}`)
      .then(r => r.ok ? r.json() : null)
      .then(d => setSensitivity(d))
      .catch(() => {});
  }, [API]);

  // Run
  const onRun = () => {
    setRunError(null);
    if (configError) return;
    const body = {
      strategy: strategy || 'all',
      total_period_years: totalPeriod,
      train_window_years: trainWindow,
      test_window_years: testWindow,
      step_months: stepMonths,
    };
    if (symbolList.trim()) {
      body.symbol_list = symbolList.split(',').map(s => s.trim()).filter(Boolean);
    }
    setRunningJob(null);
    setProgress(null);
    setResults(null);
    setSensitivity(null);
    setResultsError(null);

    authFetch(`${API}/walk-forward/run`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    })
      .then(r => { if (!r.ok) throw new Error(r.statusText); return r.json(); })
      .then(d => {
        if (d.status === 'running' && d.job_id) {
          setRunningJob(d);
          setRunStartTime(Date.now());
          setProgress({ job_id: d.job_id, pct: 0, window: 0, total_windows: 0, phase: 'starting', status: 'running' });
        } else if (d.status === 'rejected') {
          setRunError(d.message || 'Rejected');
        } else {
          throw new Error('Unexpected response');
        }
      })
      .catch(e => {
        if (e.message === 'Unauthorized') {
          setRunError('Authentication required. Please log in to run walk-forward analysis.');
        } else {
          setRunError(e.message || 'Failed to start walk-forward analysis. Check that the backend is running.');
        }
      });
  };

  // Delete
  const onDelete = (jobId) => {
    if (!window.confirm('Delete this analysis?')) return;
    authFetch(`${API}/walk-forward/results/${jobId}`, { method: 'DELETE' })
      .then(() => {
        fetchHistory();
        if (selectedJobId === jobId) { setResults(null); setSensitivity(null); setSelectedJobId(null); }
      })
      .catch(() => {});
  };

  /* ── Derived data ──────────────────────────────────────── */
  const agg = results?.aggregate || {};
  const ofSum = results?.overfitting_summary || {};
  const pStab = results?.parameter_stability || {};
  const ci = results?.confidence_intervals || {};
  const windows = results?.windows || [];

  // Compute aggregate train metrics from windows for comparison
  const trainAgg = (() => {
    if (!windows.length) return {};
    const vals = {
      pf: [], wr: [], sharpe: [], pnl: [], trades: [], maxDD: [],
    };
    windows.forEach(w => {
      const tm = w.train_metrics || {};
      if (tm.pf != null) vals.pf.push(tm.pf);
      if (tm.win_rate != null) vals.wr.push(tm.win_rate);
      if (tm.sharpe != null) vals.sharpe.push(tm.sharpe);
      if (tm.total_pnl != null) vals.pnl.push(tm.total_pnl);
      if (tm.total_trades != null) vals.trades.push(tm.total_trades);
      if (tm.max_drawdown_pct != null) vals.maxDD.push(tm.max_drawdown_pct);
    });
    const avg = arr => arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : null;
    const sum = arr => arr.length ? arr.reduce((a, b) => a + b, 0) : null;
    return {
      pf: avg(vals.pf),
      wr: avg(vals.wr),
      sharpe: avg(vals.sharpe),
      pnl: sum(vals.pnl),
      trades: sum(vals.trades),
      maxDD: vals.maxDD.length ? Math.max(...vals.maxDD.map(Math.abs)) : null,
    };
  })();

  const TABS = [
    { key: 'overview', label: 'Overview' },
    { key: 'comparison', label: 'Train vs Test' },
    { key: 'windows', label: 'Windows' },
    { key: 'stability', label: 'Stability' },
    { key: 'oos', label: 'OOS Metrics' },
    { key: 'sensitivity', label: 'Sensitivity' },
  ];

  return (
    <div className={s.page}>
      {/* Header */}
      <div className={s.headerRow}>
        <h1 className={s.headerTitle}>Walk-Forward Optimizer</h1>
        <div className={s.headerSub}>Rolling train/test validation</div>
      </div>

      <div className={s.mainLayout}>
        {/* ── LEFT: Config + Results ──────────────────────── */}
        <div className={s.leftColumn}>

          {/* Config Panel */}
          <Card>
            <h2 className={s.configTitle}>Configuration</h2>
            <div className={s.configGrid}>
              <div>
                <label className={s.inputLabel}>Strategy</label>
                <select value={strategy} onChange={e => setStrategy(e.target.value)}
                  className={s.input} style={{ cursor: 'pointer' }}>
                  <option value="all">All Strategies</option>
                  {strategies.map(st => <option key={st} value={st}>{st}</option>)}
                </select>
              </div>
              <div>
                <label className={s.inputLabel}>Symbols (optional)</label>
                <input type="text" value={symbolList} onChange={e => setSymbolList(e.target.value)}
                  placeholder="AAPL,MSFT,GOOG" className={s.input} spellCheck={false} />
              </div>
              <div>
                <label className={s.inputLabel}>Total Period: {totalPeriod}y</label>
                <input type="range" min={2} max={30} step={1} value={totalPeriod}
                  onChange={e => setTotalPeriod(+e.target.value)} className={s.rangeInput} />
              </div>
              <div>
                <label className={s.inputLabel}>Train Window: {trainWindow.toFixed(1)}y</label>
                <input type="range" min={0.5} max={10} step={0.5} value={trainWindow}
                  onChange={e => setTrainWindow(+e.target.value)} className={s.rangeInput} />
              </div>
              <div>
                <label className={s.inputLabel}>Test Window: {testWindow.toFixed(1)}y</label>
                <input type="range" min={0.25} max={5} step={0.25} value={testWindow}
                  onChange={e => setTestWindow(+e.target.value)} className={s.rangeInput} />
              </div>
              <div>
                <label className={s.inputLabel}>Step Size: {stepMonths}mo</label>
                <input type="range" min={1} max={24} step={1} value={stepMonths}
                  onChange={e => setStepMonths(+e.target.value)} className={s.rangeInput} />
              </div>
            </div>
            {configError && <div className={s.configErrorText}>{configError}</div>}
            <div className={s.configActions}>
              <button onClick={onRun} disabled={!!configError || !!runningJob}
                className={s.runButton}
                style={{
                  background: (configError || runningJob) ? C.border : C.blue,
                  cursor: (configError || runningJob) ? 'not-allowed' : 'pointer',
                }}>
                {runningJob ? <><Spinner size={16} color="#fff" /> Running...</> : 'Run Walk-Forward'}
              </button>
              {runError && <span className={s.runErrorText}>{runError}</span>}
            </div>
          </Card>

          {/* Progress */}
          {progress && progress.status === 'running' && (
            <Card>
              <ProgressBar
                pct={progress.pct}
                window={progress.window}
                totalWindows={progress.total_windows}
                phase={progress.phase}
                startTime={runStartTime}
              />
            </Card>
          )}

          {/* Loading */}
          {resultsLoading && (
            <Card className={s.cardCenter}>
              <Spinner size={24} color={C.blue} />
              <div className={s.cardCenterText}>Loading results...</div>
            </Card>
          )}

          {/* Error */}
          {resultsError && (
            <Card className={s.cardError}>
              <span className={s.cardErrorText}>Error: {resultsError}</span>
            </Card>
          )}

          {/* Empty state */}
          {!results && !resultsLoading && !resultsError && !runningJob && (
            <Card className={s.emptyCard}>
              <div className={s.emptyIcon}>
                <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
                  <rect x="4" y="12" width="16" height="32" rx="2" fill={C.blue} opacity="0.15" stroke={C.blue} strokeWidth="1.5" />
                  <rect x="24" y="4" width="16" height="40" rx="2" fill={C.green} opacity="0.15" stroke={C.green} strokeWidth="1.5" />
                  <line x1="4" y1="28" x2="40" y2="28" stroke={C.muted} strokeDasharray="3,3" />
                </svg>
              </div>
              <div className={s.emptyTitle}>Walk-Forward Optimizer</div>
              <div className={s.emptyDesc}>
                Configure your rolling train/test window parameters above, then click "Run Walk-Forward" to analyze
                how well strategy parameters generalize across time periods. Select a past analysis from the history
                panel on the right to view results.
              </div>
            </Card>
          )}

          {/* ── Results ─────────────────────────────────────── */}
          {results && results.status !== 'running' && (
            <>
              {/* Tabs */}
              <div className={s.tabBar}>
                {TABS.map(t => (
                  <button key={t.key} onClick={() => setTab(t.key)}
                    className={`${s.tabButton} ${tab === t.key ? s.tabActive : s.tabInactive}`}>
                    {t.label}
                  </button>
                ))}
              </div>

              {/* ─── TAB: Overview ─── */}
              {tab === 'overview' && (
                <Card>
                  <h2 className={s.overviewTitle}>
                    {results.strategy || 'all'} -- Walk-Forward Results
                  </h2>
                  <div className={s.overviewSub}>
                    {results.valid_windows ?? 0}/{results.total_windows ?? 0} windows | {fmt(results.elapsed_sec, 1)}s
                  </div>

                  {/* Top-level OOS metrics */}
                  <div className={s.metricsRow}>
                    <Metric label="OOS Profit Factor" value={fmtPF(agg.oos_profit_factor)}
                      color={valColor(agg.oos_profit_factor, 1.5, 1)} />
                    <Metric label="OOS Win Rate" value={fmtPct(agg.oos_win_rate)}
                      color={valColor(agg.oos_win_rate, 50, 40)} />
                    <Metric label="OOS Sharpe" value={fmt(agg.oos_sharpe, 2)}
                      color={valColor(agg.oos_sharpe, 1, 0)} />
                    <Metric label="OOS Max DD" value={fmtPct(agg.oos_max_drawdown_pct)}
                      color={C.red} />
                    <Metric label="OOS Total PnL" value={fmtDollar(agg.oos_total_pnl)}
                      color={agg.oos_total_pnl >= 0 ? C.green : C.red} />
                    <Metric label="OOS Trades" value={agg.oos_total_trades || 0} color={C.text} />
                  </div>

                  {/* Overfitting assessment */}
                  {ofSum.assessment && (
                    <div className={s.overfittingBox} style={{
                      background: `${assessColor(ofSum.assessment)}18`,
                      border: `1px solid ${assessColor(ofSum.assessment)}40`,
                    }}>
                      <div className={s.overfittingTitle} style={{ color: assessColor(ofSum.assessment) }}>
                        Overfitting: {ofSum.assessment?.replace(/_/g, ' ')} (ratio: {fmt(ofSum.avg_overall, 3)})
                      </div>
                      <div className={s.overfittingDesc}>{ofSum.description}</div>
                    </div>
                  )}

                  {/* Stability score + window heatmap */}
                  <div className={s.overviewStabilityRow}>
                    <div className={s.overviewStabilityLeft}>
                      <StabilityGauge score={pStab.overall_stability_score} label="Parameter Stability" />
                    </div>
                    <div className={s.overviewStabilityRight}>
                      <StabilityHeatmap windows={windows} />
                    </div>
                  </div>

                  {/* Train vs Test quick bar chart */}
                  <h3 className={s.sectionH3}>Train vs Test PF by Window</h3>
                  <WindowBarChart windows={windows} />

                  <h3 className={s.sectionH3} style={{ marginTop: 20 }}>Out-of-Sample Equity Curve</h3>
                  <EquityCurve windows={windows} />
                </Card>
              )}

              {/* ─── TAB: Train vs Test Comparison ─── */}
              {tab === 'comparison' && (
                <Card>
                  <h3 className={s.sectionH3} style={{ marginBottom: 4 }}>Train vs Test Performance</h3>
                  <div className={s.compSubtext}>
                    Side-by-side aggregate metrics averaged across all {windows.length} windows.
                    Smaller degradation from train to test = better generalization.
                  </div>

                  <div className={s.compGrid}>
                    <ComparisonMetric
                      label="Profit Factor"
                      trainVal={trainAgg.pf}
                      testVal={agg.oos_profit_factor}
                      formatter={fmtPF}
                      goodThreshold={1.5}
                      warnThreshold={1}
                    />
                    <ComparisonMetric
                      label="Win Rate"
                      trainVal={trainAgg.wr}
                      testVal={agg.oos_win_rate}
                      formatter={fmtPct}
                      goodThreshold={55}
                      warnThreshold={45}
                    />
                    <ComparisonMetric
                      label="Sharpe Ratio"
                      trainVal={trainAgg.sharpe}
                      testVal={agg.oos_sharpe}
                      formatter={v => fmt(v, 2)}
                      goodThreshold={1}
                      warnThreshold={0}
                    />
                    <ComparisonMetric
                      label="Total PnL"
                      trainVal={trainAgg.pnl}
                      testVal={agg.oos_total_pnl}
                      formatter={fmtDollar}
                      goodThreshold={0}
                      warnThreshold={-1000}
                    />
                    <ComparisonMetric
                      label="Total Trades"
                      trainVal={trainAgg.trades}
                      testVal={agg.oos_total_trades}
                      formatter={v => fmt(v, 0)}
                    />
                    <ComparisonMetric
                      label="Max Drawdown"
                      trainVal={trainAgg.maxDD}
                      testVal={agg.oos_max_drawdown_pct}
                      formatter={v => fmtPct(v)}
                      higherIsBetter={false}
                    />
                  </div>

                  {/* Per-window comparison table */}
                  <h3 className={s.sectionH3} style={{ marginTop: 24, marginBottom: 8 }}>Per-Window Comparison</h3>
                  <div style={{ overflowX: 'auto' }}>
                    <table className={s.windowsTable}>
                      <thead>
                        <tr>
                          <th style={{ textAlign: 'center' }}>Window</th>
                          <th style={{ textAlign: 'center' }} colSpan={3}>--- Train ---</th>
                          <th style={{ textAlign: 'center' }} colSpan={3}>--- Test ---</th>
                          <th style={{ textAlign: 'center' }}>Degradation</th>
                        </tr>
                        <tr>
                          <th>#</th>
                          <th>PF</th><th>WR</th><th>Sharpe</th>
                          <th>PF</th><th>WR</th><th>Sharpe</th>
                          <th>PF Ratio</th>
                        </tr>
                      </thead>
                      <tbody>
                        {windows.map(w => {
                          const tm = w.train_metrics || {};
                          const tsm = w.test_metrics || {};
                          const testPF = tsm.pf || 0;
                          const trainPF = tm.pf || 0;
                          const ratio = trainPF > 0 ? testPF / trainPF : null;
                          const bad = testPF < 1;
                          return (
                            <tr key={w.window_id} style={{ background: bad ? `${C.red}10` : 'transparent' }}>
                              <td className={s.tdCenter}>{w.window_id}</td>
                              <td className={s.tdRight} style={{ color: C.blue }}>{fmtPF(trainPF)}</td>
                              <td className={s.tdRight} style={{ color: C.blue }}>{fmt(tm.win_rate, 1)}%</td>
                              <td className={s.tdRight} style={{ color: C.blue }}>{fmt(tm.sharpe, 2)}</td>
                              <td className={s.tdRight} style={{ color: bad ? C.red : C.green }}>{fmtPF(testPF)}</td>
                              <td className={s.tdRight} style={{ color: bad ? C.red : C.green }}>{fmt(tsm.win_rate, 1)}%</td>
                              <td className={s.tdRight} style={{ color: bad ? C.red : C.green }}>{fmt(tsm.sharpe, 2)}</td>
                              <td className={s.tdRight} style={{
                                color: ratio != null ? (ratio >= 0.8 ? C.green : ratio >= 0.5 ? C.amber : C.red) : C.muted,
                                fontWeight: 700,
                              }}>
                                {ratio != null ? fmt(ratio, 2) : '-'}
                              </td>
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>
                </Card>
              )}

              {/* ─── TAB: Windows ─── */}
              {tab === 'windows' && (
                <Card style={{ overflowX: 'auto' }}>
                  <h3 className={s.sectionH3} style={{ marginBottom: 12 }}>Window-by-Window Breakdown</h3>
                  <table className={s.windowsTable}>
                    <thead>
                      <tr>
                        {['#', 'Train Period', 'Test Period', 'Train Sigs', 'Test Sigs',
                          'Train PF', 'Test PF', 'Train WR', 'Test WR', 'OFR PF', 'SL', 'TP', 'Hold'].map(h => (
                          <th key={h}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {windows.map(w => {
                        const testPF = w.test_metrics?.pf || 0;
                        const bad = testPF < 1;
                        return (
                          <tr key={w.window_id} style={{ background: bad ? `${C.red}10` : 'transparent' }}>
                            <td className={s.tdCenter}>{w.window_id}</td>
                            <td className={s.tdDate}>{w.train_start} - {w.train_end}</td>
                            <td className={s.tdDate}>{w.test_start} - {w.test_end}</td>
                            <td className={s.tdRight}>{w.train_signals}</td>
                            <td className={s.tdRight}>{w.test_signals}</td>
                            <td className={s.tdRight} style={{ color: C.blue }}>{fmtPF(w.train_metrics?.pf)}</td>
                            <td className={s.tdRight} style={{ color: bad ? C.red : C.green }}>{fmtPF(testPF)}</td>
                            <td className={s.tdRight}>{fmt(w.train_metrics?.win_rate, 1)}%</td>
                            <td className={s.tdRight} style={{ color: bad ? C.red : C.text }}>{fmt(w.test_metrics?.win_rate, 1)}%</td>
                            <td className={s.tdRight} style={{ color: assessColor(ofSum.assessment) }}>{fmt(w.overfitting_ratio_pf, 3)}</td>
                            <td className={s.tdRight}>{w.best_params?.stop_loss}</td>
                            <td className={s.tdRight}>{w.best_params?.take_profit}</td>
                            <td className={s.tdRight}>{w.best_params?.max_hold_days}</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>

                  {/* Window pass/fail strip */}
                  <div style={{ marginTop: 16 }}>
                    <StabilityHeatmap windows={windows} />
                  </div>
                </Card>
              )}

              {/* ─── TAB: Stability ─── */}
              {tab === 'stability' && (
                <Card>
                  <h3 className={s.stabilityH3}>Parameter Stability</h3>
                  <div className={s.stabilitySub}>
                    How much optimal parameters drift across rolling windows. Low CV = stable parameters.
                  </div>

                  {/* Stability gauge */}
                  <div className={s.stabilityGaugeRow}>
                    <StabilityGauge score={pStab.overall_stability_score} label="Overall Stability Score" />
                    <div className={s.stabilityInterpretation}>
                      <div className={s.stabilityInterpTitle}>
                        {pStab.interpretation || 'N/A'}
                      </div>
                      <div className={s.stabilityInterpDesc}>
                        {pStab.overall_stability_score >= 0.7
                          ? 'Parameters remain consistent across windows. The strategy is likely robust and not overfit to specific time periods.'
                          : pStab.overall_stability_score >= 0.4
                          ? 'Parameters show moderate variation. Some windows required different optimal values, suggesting partial sensitivity to market conditions.'
                          : 'Parameters change significantly across windows. The strategy may be overfit to specific time periods or market regimes.'}
                      </div>
                    </div>
                  </div>

                  {/* Parameter drift chart */}
                  <h3 className={s.sectionH3} style={{ marginTop: 20, marginBottom: 8 }}>Parameter Drift Across Windows</h3>
                  <ParamDriftChart paramStability={pStab} windows={windows} />

                  {/* Individual parameter cards */}
                  <h3 className={s.sectionH3} style={{ marginTop: 20, marginBottom: 8 }}>Per-Parameter Statistics</h3>
                  <div className={s.stabilityGrid}>
                    {['stop_loss', 'take_profit', 'max_hold_days', 'trailing_stop', 'min_score']
                      .filter(k => pStab[k] && typeof pStab[k] === 'object')
                      .map(k => {
                        const st = pStab[k];
                        const cvColor = st.cv < 0.15 ? C.green : st.cv < 0.3 ? C.green : st.cv < 0.6 ? C.amber : C.red;
                        const cvLabel = st.cv < 0.15 ? 'Very Stable' : st.cv < 0.3 ? 'Stable' : st.cv < 0.6 ? 'Variable' : 'Unstable';
                        return (
                          <div key={k} className={s.stabilityCard}>
                            <div className={s.stabilityCardHeader}>
                              <div className={s.stabilityCardTitle}>{k.replace(/_/g, ' ')}</div>
                              <div className={s.stabilityBadge} style={{ background: `${cvColor}20`, color: cvColor }}>
                                {cvLabel}
                              </div>
                            </div>
                            <div className={s.stabilityCardGrid}>
                              <span className={s.stabilityCardLabel}>Mean:</span>
                              <span className={s.stabilityCardValue}>{fmt(st.mean, 2)}</span>
                              <span className={s.stabilityCardLabel}>Std:</span>
                              <span className={s.stabilityCardValue}>{fmt(st.std, 3)}</span>
                              <span className={s.stabilityCardLabel}>CV:</span>
                              <span className={s.stabilityCardValue} style={{ color: cvColor }}>
                                {fmt(st.cv, 3)}
                              </span>
                              <span className={s.stabilityCardLabel}>Range:</span>
                              <span className={s.stabilityCardValue}>[{st.min}, {st.max}]</span>
                              <span className={s.stabilityCardLabel}>Most Common:</span>
                              <span className={s.stabilityCardValue}>{st.most_common}</span>
                            </div>
                            <div className={s.sparklineRow}>
                              <span className={s.sparklineLabel}>Trend</span>
                              <ParamSparkline values={st.values} color={cvColor} width={160} height={28} />
                            </div>
                          </div>
                        );
                      })}
                  </div>
                </Card>
              )}

              {/* ─── TAB: OOS Metrics ─── */}
              {tab === 'oos' && (
                <Card>
                  <h3 className={s.sectionH3} style={{ marginBottom: 4 }}>Out-of-Sample Performance</h3>
                  <div className={s.compSubtext}>
                    These metrics are computed exclusively from test (out-of-sample) data -- the model never saw this data during training.
                  </div>

                  {/* Primary OOS metrics */}
                  <div className={s.metricsRow} style={{ marginTop: 16 }}>
                    <Metric label="Profit Factor" value={fmtPF(agg.oos_profit_factor)}
                      color={valColor(agg.oos_profit_factor, 1.5, 1)}
                      sub={agg.oos_profit_factor >= 1.5 ? 'Strong' : agg.oos_profit_factor >= 1 ? 'Positive' : 'Negative'} />
                    <Metric label="Win Rate" value={fmtPct(agg.oos_win_rate)}
                      color={valColor(agg.oos_win_rate, 55, 45)}
                      sub={agg.oos_win_rate >= 55 ? 'Above avg' : agg.oos_win_rate >= 45 ? 'Average' : 'Below avg'} />
                    <Metric label="Sharpe Ratio" value={fmt(agg.oos_sharpe, 2)}
                      color={valColor(agg.oos_sharpe, 1, 0)}
                      sub={agg.oos_sharpe >= 2 ? 'Excellent' : agg.oos_sharpe >= 1 ? 'Good' : agg.oos_sharpe >= 0 ? 'Fair' : 'Poor'} />
                  </div>

                  <div className={s.metricsRow}>
                    <Metric label="Total PnL" value={fmtDollar(agg.oos_total_pnl)}
                      color={agg.oos_total_pnl >= 0 ? C.green : C.red} />
                    <Metric label="Max Drawdown" value={fmtPct(agg.oos_max_drawdown_pct)}
                      color={C.red}
                      sub={agg.oos_max_drawdown_pct <= 10 ? 'Low risk' : agg.oos_max_drawdown_pct <= 20 ? 'Moderate' : 'High risk'} />
                    <Metric label="Total Trades" value={agg.oos_total_trades || 0}
                      color={C.text}
                      sub={`${windows.length} windows`} />
                  </div>

                  {/* 95% Confidence Intervals */}
                  <h3 className={s.sectionH3} style={{ marginTop: 24 }}>95% Confidence Intervals</h3>
                  <div className={s.compSubtext} style={{ marginBottom: 12 }}>
                    Based on distribution of per-window out-of-sample metrics.
                  </div>
                  <CIBar label="Profit Factor" ci={ci.profit_factor} />
                  <CIBar label="Win Rate" ci={ci.win_rate} unit="%" />
                  <CIBar label="Sharpe Ratio" ci={ci.sharpe} />
                  <CIBar label="Avg Return" ci={ci.avg_return} unit="%" />
                  <CIBar label="Max Drawdown" ci={ci.max_drawdown_pct} unit="%" />

                  {/* Overfitting Ratios */}
                  <h4 className={s.overfitH4}>Overfitting Ratios (test/train)</h4>
                  <div className={s.compSubtext} style={{ marginBottom: 12 }}>
                    Values close to 1.0 indicate good generalization. Below 0.5 suggests significant overfitting.
                  </div>
                  <div className={s.overfitGrid}>
                    <Metric label="PF Ratio" value={fmt(ofSum.avg_overfitting_ratio_pf, 3)}
                      color={valColor(ofSum.avg_overfitting_ratio_pf, 0.8, 0.5)}
                      sub={`n=${ofSum.windows_analyzed || 0}`} />
                    <Metric label="WR Ratio" value={fmt(ofSum.avg_overfitting_ratio_wr, 3)}
                      color={valColor(ofSum.avg_overfitting_ratio_wr, 0.8, 0.5)} />
                    <Metric label="Sharpe Ratio" value={fmt(ofSum.avg_overfitting_ratio_sharpe, 3)}
                      color={valColor(ofSum.avg_overfitting_ratio_sharpe, 0.8, 0.5)} />
                  </div>

                  {ofSum.pf_ratios && ofSum.pf_ratios.length > 0 && (
                    <div className={s.pfRatioSpark}>
                      <div className={s.pfRatioLabel}>PF Overfit Ratio per Window (1.0 = perfect generalization)</div>
                      <ParamSparkline values={ofSum.pf_ratios} color={C.amber} width={500} height={40} />
                    </div>
                  )}

                  {/* OOS Equity */}
                  <h3 className={s.sectionH3} style={{ marginTop: 24 }}>OOS Equity Curve</h3>
                  <EquityCurve windows={windows} />
                </Card>
              )}

              {/* ─── TAB: Sensitivity ─── */}
              {tab === 'sensitivity' && (
                <Card>
                  <h3 className={s.sensitivityH3}>Parameter Sensitivity Analysis</h3>
                  <div className={s.sensitivitySub}>
                    How each parameter value correlates with out-of-sample performance across windows.
                    Strong correlation means the strategy is sensitive to that parameter.
                  </div>
                  {(!sensitivity || !sensitivity.sensitivity || Object.keys(sensitivity.sensitivity).length === 0) ? (
                    <div className={s.sensitivityNoData}>
                      {sensitivity?.error || 'No sensitivity data available. Need at least 2 completed windows with varying parameter values.'}
                    </div>
                  ) : (
                    <>
                      {/* Summary table */}
                      <div style={{ overflowX: 'auto', marginBottom: 20 }}>
                        <table className={s.windowsTable} style={{ minWidth: 600 }}>
                          <thead>
                            <tr>
                              <th style={{ textAlign: 'left' }}>Parameter</th>
                              <th>Best Value</th>
                              <th>Best OOS PF</th>
                              <th>Correlation</th>
                              <th>Mean</th>
                              <th>Std</th>
                              <th>Impact</th>
                            </tr>
                          </thead>
                          <tbody>
                            {Object.entries(sensitivity.sensitivity).map(([pk, data]) => {
                              const absCorr = Math.abs(data.correlation_pf || 0);
                              const impact = absCorr > 0.7 ? 'High' : absCorr > 0.3 ? 'Medium' : 'Low';
                              const impactColor = absCorr > 0.7 ? C.red : absCorr > 0.3 ? C.amber : C.green;
                              return (
                                <tr key={pk}>
                                  <td style={{ textTransform: 'capitalize', textAlign: 'left' }}>{pk.replace(/_/g, ' ')}</td>
                                  <td className={s.tdRight} style={{ color: C.green, fontWeight: 700 }}>{data.best_value}</td>
                                  <td className={s.tdRight} style={{ color: C.green }}>{fmt(data.best_oos_pf, 3)}</td>
                                  <td className={s.tdRight} style={{ color: absCorr > 0.5 ? C.amber : C.muted }}>
                                    {fmt(data.correlation_pf, 3)}
                                  </td>
                                  <td className={s.tdRight}>{data.mean}</td>
                                  <td className={s.tdRight}>{fmt(data.std, 3)}</td>
                                  <td className={s.tdCenter}>
                                    <span style={{ fontSize: 11, fontWeight: 700, padding: '2px 8px', borderRadius: 4, background: `${impactColor}20`, color: impactColor }}>
                                      {impact}
                                    </span>
                                  </td>
                                </tr>
                              );
                            })}
                          </tbody>
                        </table>
                      </div>

                      {/* Per-parameter detail cards with charts */}
                      <div className={s.sensitivityGrid}>
                        {Object.entries(sensitivity.sensitivity).map(([pk, data]) => (
                          <div key={pk} className={s.sensitivityCard}>
                            <div className={s.sensitivityCardTitle}>{pk.replace(/_/g, ' ')}</div>
                            <div className={s.sensitivityCardGrid}>
                              <span className={s.sensitivityCardLabel}>Best Value:</span>
                              <span className={s.sensitivityCardValue} style={{ color: C.green }}>{data.best_value}</span>
                              <span className={s.sensitivityCardLabel}>Best OOS PF:</span>
                              <span className={s.sensitivityCardValue} style={{ color: C.green }}>{fmt(data.best_oos_pf, 3)}</span>
                              <span className={s.sensitivityCardLabel}>Corr w/ PF:</span>
                              <span className={s.sensitivityCardValue} style={{
                                color: Math.abs(data.correlation_pf) > 0.5 ? C.amber : C.muted }}>
                                {fmt(data.correlation_pf, 3)}
                              </span>
                              <span className={s.sensitivityCardLabel}>Mean:</span>
                              <span className={s.sensitivityCardValue}>{data.mean}</span>
                              <span className={s.sensitivityCardLabel}>Std:</span>
                              <span className={s.sensitivityCardValue}>{fmt(data.std, 3)}</span>
                            </div>
                            <div className={s.sensitivityChartLabel}>OOS PF by parameter value</div>
                            <SensitivityChart data={data} />
                          </div>
                        ))}
                      </div>
                    </>
                  )}
                </Card>
              )}
            </>
          )}
        </div>

        {/* ── RIGHT: History sidebar ─────────────────────── */}
        <div className={s.sidebar}>
          <Card className={s.sidebarCard}>
            <h3 className={s.sidebarTitle}>History</h3>

            {/* Running jobs */}
            {runningJobs.length > 0 && (
              <div className={s.runningSection}>
                <div className={s.runningBadge}>Running</div>
                {runningJobs.map(r => (
                  <div key={r.job_id} className={s.runningItem}>
                    <div className={s.runningStrategy}>{r.strategy || 'all'}</div>
                    <ProgressBar pct={r.pct} />
                    <span className={s.runningPct}>{fmt(r.pct, 0)}% ({r.window}/{r.total_windows})</span>
                  </div>
                ))}
              </div>
            )}

            {/* Completed */}
            {history.length === 0 && runningJobs.length === 0 && (
              <div className={s.emptyHistory}>
                No walk-forward analyses yet. Configure parameters on the left and click "Run Walk-Forward" to start.
              </div>
            )}
            {history.map(h => {
              const isSelected = selectedJobId === h.job_id;
              return (
                <div key={h.job_id}
                  onClick={() => loadResults(h.job_id)}
                  className={`${s.historyItem} ${isSelected ? s.historyItemSelected : ''}`}>
                  <div className={s.historyItemHeader}>
                    <span className={s.historyItemStrategy}>
                      {h.strategy || 'all'}
                    </span>
                    <button onClick={e => { e.stopPropagation(); onDelete(h.job_id); }}
                      className={s.historyDeleteBtn}
                      title="Delete">x</button>
                  </div>
                  <div className={s.historyItemMeta}>
                    {h.valid_windows || 0}/{h.total_windows || 0} windows
                    {h.created_at ? ` | ${fmtDate(h.created_at)}` : ''}
                  </div>
                  <div className={s.historyItemStats}>
                    {h.aggregate?.oos_profit_factor != null && (
                      <span style={{ fontFamily: mono, color: h.aggregate.oos_profit_factor >= 1 ? C.green : C.red }}>
                        PF {fmtPF(h.aggregate.oos_profit_factor)}
                      </span>
                    )}
                    {h.overfitting_summary?.assessment && (
                      <span className={s.historyBadge} style={{
                        background: `${assessColor(h.overfitting_summary.assessment)}20`,
                        color: assessColor(h.overfitting_summary.assessment),
                      }}>
                        {h.overfitting_summary.assessment?.replace(/_/g, ' ')}
                      </span>
                    )}
                  </div>
                </div>
              );
            })}
          </Card>
        </div>
      </div>
    </div>
  );
}
